import { useState, createContext } from "react";
import { useContext } from "react";
import { useEffect } from "react";

const OrderContext = createContext();

export const OrderProvider = ({ children }) => {
  const [order, setOrders] = useState({});
  const [menu, setMenu] =useState(null);

//   const UpdateOrder = (productID, quantity) => {
//     setOrders(prevOrders => ({
//       ...prevOrders,
//       [productID]: (prevOrders[productID] || 0) + quantity // Adds quantity or sets it if not present
//     }));
//   };

  const addToOrder = (productID, quantity) => {
    setOrder(prevOrder => ({
      ...prevOrder,
      [productID]: (prevOrder[productID] || 0) + quantity // Add to existing quantity or set it if not present
    }));
  };

  useEffect(() => {
    console.log("Updated Order:", order);
  }, [order]);

  useEffect(() => {
    console.log("Menu:", menu);
  }, [menu]);

  return (
    <OrderContext.Provider value={{ order, addToOrder ,menu , setMenu}}>
      {children}
    </OrderContext.Provider>
  );
};

export const useOrderContext  =() =>{
    return (useContext(OrderContext));
}
